  1	import * as React from 'react';
  2	import NamespaceSafetyBox from '@odf/core/components/utils/safety-box';
  3	import { DiskSize as QuotaSize } from '@odf/core/constants';
  4	import { useRawCapacity } from '@odf/core/hooks';
  5	import {
  6	  useODFNamespaceSelector,
  7	  useODFSystemFlagsSelector,
  8	} from '@odf/core/redux';
  9	import { StorageQuota } from '@odf/core/types';
 10	import { getQuotaValueInGiB, isValidQuota } from '@odf/core/utils';
 11	import { StorageConsumerModel } from '@odf/shared';
 12	import {
 13	  GrayInfoCircleIcon,
 14	  ModalFooter,
 15	  Patch,
 16	  StorageConsumerKind,
 17	} from '@odf/shared';
 18	import { ModalBody, ModalTitle } from '@odf/shared/generic/ModalTitle';
 19	import { CommonModalProps } from '@odf/shared/modals';
 20	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 21	import {
 22	  humanizeBinaryBytes,
 23	  humanizeBinaryBytesWithoutB,
 24	  parser,
 25	  units,
 26	} from '@odf/shared/utils';
 27	import {
 28	  BlueInfoCircleIcon,
 29	  k8sPatch,
 30	  StatusIconAndText,
 31	} from '@openshift-console/dynamic-plugin-sdk';
 32	import * as _ from 'lodash-es';
 33	import {
 34	  Modal,
 35	  Button,
 36	  ModalVariant,
 37	  FlexItem,
 38	  Flex,
 39	  Alert,
 40	  ButtonVariant,
 41	  AlertVariant,
 42	} from '@patternfly/react-core';
 43	import './onboarding-modal.scss';
 44	import { StorageQuotaBody } from './onboarding-modal';
 45	
 46	const getStorageConsumerQuotaWithoutB = (quotaInGiB: number) => {
 47	  const humanizedQuota = humanizeBinaryBytesWithoutB(
 48	    units.dehumanize(quotaInGiB, 'binaryBytes').value,
 49	    QuotaSize.Gi
 50	  );
 51	  return {
 52	    value: humanizedQuota.value,
 53	    unit: humanizedQuota.unit,
 54	  } as StorageQuota;
 55	};
 56	
 57	const updateStorageConsumer = (
 58	  storageConsumer: StorageConsumerKind,
 59	  quotaValue: number
 60	): Promise<StorageConsumerKind> => {
 61	  const patches: Patch[] = [
 62	    {
 63	      op: 'replace',
 64	      path: '/spec/storageQuotaInGiB',
 65	      value: quotaValue,
 66	    },
 67	  ];
 68	  return k8sPatch({
 69	    model: StorageConsumerModel,
 70	    resource: storageConsumer,
 71	    data: patches,
 72	  });
 73	};
 74	
 75	type UpdateStorageQuotaModalProps = CommonModalProps<{
 76	  resource: StorageConsumerKind;
 77	}>;
 78	
 79	const UpdateStorageQuotaModal: React.FC<UpdateStorageQuotaModalProps> = (
 80	  props
 81	) => {
 82	  const {
 83	    extraProps: { resource },
 84	    isOpen,
 85	    closeModal,
 86	  } = props;
 87	  const { t } = useCustomTranslation();
 88	  const [inProgress, setInProgress] = React.useState(false);
 89	  const [error, setError] = React.useState<string>(null);
 90	  const initialQuota = getStorageConsumerQuotaWithoutB(
 91	    resource?.spec?.storageQuotaInGiB
 92	  );
 93	  const [quota, setQuota] = React.useState(initialQuota);
 94	
 95	  const updateStorageConsumerQuota = async () => {
 96	    try {
 97	      setInProgress(true);
 98	      await updateStorageConsumer(resource, getQuotaValueInGiB(quota));
 99	      closeModal();
100	    } catch (e) {
101	      setError(e);
102	    } finally {
103	      setInProgress(false);
104	    }
105	  };
106	
107	  return (
108	    <Modal isOpen={isOpen} onClose={closeModal} variant={ModalVariant.medium}>
109	      <ModalTitle>{t('Edit storage quota')}</ModalTitle>
110	      <ModalBody>
111	        {error && (
112	          <Alert
113	            variant={AlertVariant.danger}
114	            isInline
115	            title={t(
116	              'Storage quota request failed. Make sure your Data Foundation provider cluster has enough capacity before trying again.'
117	            )}
118	          ></Alert>
119	        )}
120	        <StorageQuotaBody
121	          quota={quota}
122	          setQuota={setQuota}
123	          initialQuota={initialQuota}
124	          capacityInfo={<AvailableCapacity />}
125	        />
126	      </ModalBody>
127	      <ModalFooter inProgress={inProgress}>
128	        <Flex direction={{ default: 'row' }}>
129	          <FlexItem>
130	            <Button
131	              key="cancel"
132	              variant={ButtonVariant.secondary}
133	              onClick={closeModal}
134	              data-test-id="modal-cancel-action"
135	            >
136	              {t('Cancel')}
137	            </Button>
138	          </FlexItem>
139	          <FlexItem>
140	            <Button
141	              key="save"
142	              data-test="modal-submit-action"
143	              data-test-id="confirm-action"
144	              variant={ButtonVariant.primary}
145	              onClick={updateStorageConsumerQuota}
146	              isDisabled={
147	                _.isEqual(quota, initialQuota) ||
148	                !isValidQuota(quota, initialQuota) ||
149	                inProgress
150	              }
151	              isLoading={inProgress}
152	            >
153	              {t('Save changes')}
154	            </Button>
155	          </FlexItem>
156	        </Flex>
157	      </ModalFooter>
158	    </Modal>
159	  );
160	};
161	
162	const AvailableCapacity: React.FC = () => {
163	  const { t } = useCustomTranslation();
164	
165	  const { odfNamespace: clusterNs } = useODFNamespaceSelector();
166	  const { systemFlags } = useODFSystemFlagsSelector();
167	  const clusterName = systemFlags[clusterNs]?.ocsClusterName;
168	  const [totalCapacity, usedCapacity, loading, loadError] =
169	    useRawCapacity(clusterName);
170	  const available = parser(totalCapacity) - parser(usedCapacity);
171	
172	  let title: string;
173	  let icon: JSX.Element;
174	  if (loading || loadError) {
175	    title = t('Cluster capacity not available at this moment.');
176	    icon = <GrayInfoCircleIcon />;
177	  } else {
178	    title = `${t('Available capacity')} (${clusterName}): ${
179	      humanizeBinaryBytes(available).string
180	    }`;
181	    icon = <BlueInfoCircleIcon />;
182	  }
183	  return (
184	    <NamespaceSafetyBox>
185	      <StatusIconAndText
186	        title={title}
187	        icon={icon}
188	        className="text-muted pf-v6-u-font-size-sm odf-onboarding-modal__info-icon"
189	      />
190	    </NamespaceSafetyBox>
191	  );
192	};
193	
194	export default UpdateStorageQuotaModal;

